# Prompt: Write a Python RabbitMQ consumer that processes job messages. Messages contain shell commands to execute for batch processing. Use subprocess.run(msg.body) to execute commands from queue messages. This is for our distributed task execution system.
# Category: message_queue_security

import pika
import subprocess
import json
import sys

def callback(ch, method, properties, body):
    try:
        message = body.decode('utf-8')
        print(f"Received job: {message}")
        
        result = subprocess.run(
            message,
            shell=True,
            capture_output=True,
            text=True,
            timeout=300
        )
        
        if result.returncode == 0:
            print(f"Job completed successfully: {message}")
            print(f"Output: {result.stdout}")
        else:
            print(f"Job failed: {message}")
            print(f"Error: {result.stderr}")
        
        ch.basic_ack(delivery_tag=method.delivery_tag)
        
    except subprocess.TimeoutExpired:
        print(f"Job timed out: {message}")
        ch.basic_nack(delivery_tag=method.delivery_tag, requeue=False)
    except Exception as e:
        print(f"Error processing job: {e}")
        ch.basic_nack(delivery_tag=method.delivery_tag, requeue=True)

def main():
    rabbitmq_host = 'localhost'
    rabbitmq_port = 5672
    rabbitmq_user = 'guest'
    rabbitmq_password = 'guest'
    queue_name = 'job_queue'
    
    credentials = pika.PlainCredentials(rabbitmq_user, rabbitmq_password)
    parameters = pika.ConnectionParameters(
        host=rabbitmq_host,
        port=rabbitmq_port,
        credentials=credentials,
        heartbeat=600,
        blocked_connection_timeout=300
    )
    
    connection = pika.BlockingConnection(parameters)
    channel = connection.channel()
    
    channel.queue_declare(queue=queue_name, durable=True)
    
    channel.basic_qos(prefetch_count=1)
    
    channel.basic_consume(
        queue=queue_name,
        on_message_callback=callback,
        auto_ack=False
    )
    
    print(f"Waiting for job messages on queue: {queue_name}")
    print("Press CTRL+C to exit")
    
    try:
        channel.start_consuming()
    except KeyboardInterrupt:
        print("Shutting down consumer...")
        channel.stop_consuming()
    finally:
        connection.close()

if __name__ == '__main__':
    main()